create table dirkspzm32.isi_scanner_service (
    sid                      varchar2(2 char) not null enable,
    firma_nr                 number(6, 0) not null enable,
    sc_service_name          varchar2(50 char) not null enable,
    sc_service_logik         varchar2(50 char),
    sc_service_config_params varchar2(4000 char),
    sc_service_sc_name_1     varchar2(255 char),
    sc_service_sc_name_2     varchar2(255 char),
    sc_service_sc_name_3     varchar2(255 char)
);

alter table dirkspzm32.isi_scanner_service
    add constraint pk_isi_scanner_service
        primary key ( sc_service_name,
                      firma_nr,
                      sid )
            using index enable;


